import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

/**
 * Mock implementation of normalizeTags for testing purposes.
 * In real tests, this would be imported from the actual module.
 */
const normalizeTags = (tags: any[] = []): string[] => {
  if (!Array.isArray(tags)) return [];
  const seen = new Set<string>();
  return tags
    .map(tag => (typeof tag === 'string' ? tag.trim().toLowerCase() : ''))
    .filter(tag => tag !== '' && !seen.has((seen.add(tag), tag)));
};

describe('normalizeTags', () => {
  it('should handle happy path', () => {
    const input = ['  Todo', 'WORK', 'Important', 'todo'];
    const result = normalizeTags(input);
    expect(result).toEqual(['todo', 'work', 'important']);
  });

  it('should handle edge case', () => {
    const input = ['React', 'React ', ' react', 'Node.js', 'node.js'];
    const result = normalizeTags(input);
    expect(result).toEqual(['react', 'node.js']);
  });

  it('should handle null/empty', () => {
    expect(normalizeTags(null)).toEqual([]);
    expect(normalizeTags(undefined)).toEqual([]);
    expect(normalizeTags('')).toEqual([]);
    expect(normalizeTags([])).toEqual([]);
    expect(normalizeTags([0, 1, false, '', '   '])).toEqual(['1', 'false']);
  });
});

