import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { sortNotesByUpdatedAt } from './sortNotesByUpdatedAt';

describe('sortNotesByUpdatedAt', () => {
  it('should handle happy path - sort multiple notes by updatedAt descending', () => {
    const notes = [
      { id: 1, updatedAt: 2 },
      { id: 2, updatedAt: 5 },
      { id: 3, updatedAt: 3 },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted).toEqual([
      { id: 2, updatedAt: 5 },
      { id: 3, updatedAt: 3 },
      { id: 1, updatedAt: 2 },
    ]);
  });

  it('should handle edge case - notes with same updatedAt should preserve original order', () => {
    const notes = [
      { id: 1, updatedAt: 4 },
      { id: 2, updatedAt: 4 },
      { id: 3, updatedAt: 5 },
    ];

    const sorted = sortNotesByUpdatedAt(notes);

    expect(sorted).toEqual([
      { id: 3, updatedAt: 5 },
      { id: 1, updatedAt: 4 },
      { id: 2, updatedAt: 4 },
    ]);
  });

  it('should handle null/empty - when given null, undefined, empty array or 0', () => {
    expect(sortNotesByUpdatedAt(null as any)).toEqual([]);
    expect(sortNotesByUpdatedAt(undefined as any)).toEqual([]);
    expect(sortNotesByUpdatedAt([])).toEqual([]);
    expect(sortNotesByUpdatedAt(0 as any)).toEqual([]);
  });
});

